方式一：使用黑色屏幕
```
#include <iostream>
#include <windows.h>

int main()
{
    HWND hwnd = GetDesktopWindow();

    HDC hdc = GetDC(hwnd);

    int width = GetSystemMetrics(SM_CXSCREEN);
    int height = GetSystemMetrics(SM_CYSCREEN);

    //创建屏幕覆盖的黑色画笔
    HBRUSH hBrush = CreateSolidBrush(RGB(0, 0, 0));

    //将屏幕用黑色数据覆盖
    FillRect(hdc, &RECT{0, 0, width, height}, hBrush);

    //释放资源
    DeleteObject(hBrush);

    ReleaseDC(hwnd, hdc);
    return 0;
}
```

方式二：使用屏幕遮罩

```
#include <iostream>
#include <corecrt_wconio.h>
#include <windows.h>

using namespace std;

int main()
{
    HWND hwnd = GetDesktopWindow();
    HDC hdc = GetDC(hwnd);

    //复制屏幕数据
    HDC memDC = CreateCompatibleDC(hdc);
    HBITMAP memBM = CreateCompatibleBitmap(hdc, GetSystemMetrics(SM_CXSCREEN), GetSystemMetrics(SM_CYSCREEN));
    SelectObject(memDC, memBM);
    BitBlt(memDC, 0, 0, GetSystemMetrics(SM_CXSCREEN), GetSystemMetrics(SM_CYSCREEN), hdc, 0, 0, SRCCOPY);

    //创建屏幕覆盖的画笔
    HBRUSH hBrush = CreateSolidBrush(RGB(0, 0, 0));

    //将创建的画笔分配给显示设备
    HBRUSH oldBrush = (HBRUSH)SelectObject(hdc, hBrush);

    //创建黑色半透明覆盖层
    AlphaBlend(hdc, 0, 0, GetSystemMetrics(SM_CXSCREEN), GetSystemMetrics(SM_CYSCREEN), hdc, 0, 0, GetSystemMetrics(SM_CXSCREEN), GetSystemMetrics(SM_CYSCREEN), BLENDFUNCTION{AC_SRC_OVER, 0, 150, AC_SRC_ALPHA});

    //释放资源
    SelectObject(hdc, oldBrush);
    DeleteObject(hBrush);
    DeleteDC(memDC);
    DeleteObject(memBM);
    ReleaseDC(hwnd, hdc);
    system("pause");
    return 0;
}
```

