使用分层窗口，可以实现一个更加高级的隐私屏，能够更好地控制显示层级和透明度。以下是一个使用分层窗口实现隐私屏的C++代码：

```
#include <iostream>
#include <windows.h>

int main()
{
    HWND hwnd = GetDesktopWindow(); //获取桌面窗口句柄
    HDC hdc = GetDC(hwnd); //获取显示设备上下文句柄

    int width = GetSystemMetrics(SM_CXSCREEN); //获取屏幕宽度
    int height = GetSystemMetrics(SM_CYSCREEN); //获取屏幕高度

    //创建分层窗口
    HWND hLayerWnd = CreateWindowEx(WS_EX_LAYERED | WS_EX_TRANSPARENT, NULL, NULL,
        WS_POPUP, 0, 0, width, height, NULL, NULL, NULL, NULL);

    HDC hLayerDC = GetDC(hLayerWnd); //获取分层窗口上下文句柄

    //创建透明画刷
    HBRUSH hBrush = CreateSolidBrush(RGB(0, 0, 0)); 
    SetLayeredWindowAttributes(hLayerWnd, RGB(0, 0, 0), 200, LWA_COLORKEY); //设置分层窗口颜色和透明度

    //绘制黑色矩形，遮盖屏幕
    FillRect(hLayerDC, &RECT{ 0, 0, width, height }, hBrush);

    DeleteObject(hBrush); //删除画刷

    ReleaseDC(hwnd, hdc); //释放句柄
    ReleaseDC(hLayerWnd, hLayerDC); //释放分层窗口句柄
    return 0;
}
```

上面的C++代码使用 `CreateWindowEx()` 方法创建一个分层窗口，使用 `GetDC()` 方法获取分层窗口的设备上下文句柄。接下来，使用 `CreateSolidBrush()` 创建一个画刷，并使用 `SetLayeredWindowAttributes()` 设置分层窗口的颜色和透明度，然后使用 `FillRect()` 方法在分层窗口上绘制黑色矩形，以遮盖屏幕。最后，删除画刷并释放相关句柄。

使用分层窗口可以实现更加高级的隐私屏，可以控制隐私屏的透明度和显示层级，从而更好地保护隐私信息。但是同样需要注意隐私保护的法律法规和道德标准，不得侵犯他人隐私权。

随着高分辨率显示器的普及，C++代码实现隐私屏需要支持高分屏才能更好地保护隐私。下面是一个使用分层窗口，并支持高分辨率屏幕的C++代码：

```
#include <iostream>
#include <windows.h>

int main()
{
    HWND hwnd = GetDesktopWindow(); //获取桌面窗口句柄
    HDC hdc = GetDC(hwnd); //获取显示设备上下文句柄

    int width = GetSystemMetrics(SM_CXSCREEN); //获取屏幕宽度
    int height = GetSystemMetrics(SM_CYSCREEN); //获取屏幕高度

    //获取系统DPI
    HDC hDCScreen = GetDC(NULL);
    int dpiX = GetDeviceCaps(hDCScreen, LOGPIXELSX);
    int dpiY = GetDeviceCaps(hDCScreen, LOGPIXELSY);
    ReleaseDC(NULL, hDCScreen);

    //创建分层窗口
    HWND hLayerWnd = CreateWindowEx(WS_EX_LAYERED | WS_EX_TRANSPARENT, NULL, NULL,
        WS_POPUP, 0, 0, MulDiv(width, 96, dpiX), MulDiv(height, 96, dpiY), NULL, NULL, NULL, NULL);

    HDC hLayerDC = GetDC(hLayerWnd); //获取分层窗口上下文句柄

    //创建透明画刷
    HBRUSH hBrush = CreateSolidBrush(RGB(0, 0, 0));
    SetLayeredWindowAttributes(hLayerWnd, RGB(0, 0, 0), 200, LWA_COLORKEY); //设置分层窗口颜色和透明度

    //绘制黑色矩形，遮盖屏幕
    FillRect(hLayerDC, &RECT{ 0, 0, MulDiv(width, 96, dpiX), MulDiv(height, 96, dpiY) }, hBrush);

    DeleteObject(hBrush); //删除画刷

    ReleaseDC(hwnd, hdc); //释放桌面窗口的设备上下文句柄
    ReleaseDC(hLayerWnd, hLayerDC); //释放分层窗口上下文句柄

    return 0;
}
```

在上述代码中，使用 `GetDeviceCaps()` 函数获取系统DPI，并使用 `MulDiv()` 函数将屏幕长宽按DPI比例缩放，保证隐私屏的正确显示。其余的代码与之前的实现类似。

